import type { TierList } from './types.ts';

export const MUTATIONS: TierList = {
  slug: 'mutations',
  title: 'Mutations',
  groups: [
    {
      label: 'Physical',
      entries: [
        { name: 'Carapace', tier: 'S', cost: 3, sprite: 'Carapace_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Carapace', review: 'Provides exceptional armor value and elemental resistances that scale incredibly with investment. Though requiring heavy point commitment, enables near-invulnerable builds and works well with both DV and AV strategies. Tightening Carapace adds utility with mental mutations and gases. Bonus turtle faction reputation is a nice extra.' },
        { name: 'Corrosive Gas Generation', tier: 'S', cost: 3, sprite: 'Corrosive_gas_generation_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Corrosive_Gas_Generation', review: 'Deals strong acid damage through lingering gas clouds that can stack for devastating effect. While highly effective against most enemies, requires careful management as gas destroys walls and can harm allies.' },
        { name: 'Double-muscled', tier: 'S', cost: 3, sprite: 'Doublemuscled_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Double-muscled', review: 'Provides valuable Strength bonus and chance to stun enemies on melee hits. Allows attribute points to be spent elsewhere while maintaining high penetration values. Particularly powerful with uncapped penetration weapons and multi-hit builds. Natural synergy with Horns and Burrowing Claws.' },
        { name: 'Multiple Legs', tier: 'S', cost: 5, sprite: 'Multiple_legs_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Multiple_Legs', review: 'A 5-point mutation granting substantial movement speed and extra carrying capacity. Movement bonus scales exceptionally with investment, allowing up to 4 moves per enemy turn. Includes two boot slots for equipment combinations and synergizes well with Ironshank by offsetting its movement penalty. While expensive, the mobility advantage makes it particularly valuable for ranged builds.' },
        { name: 'Triple-jointed', tier: 'S', cost: 3, sprite: 'Triplejointed_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Triple-jointed', review: 'Grants significant Agility bonus and chance to avoid ability cooldowns. Excels with Agility-based skills and short blades, enabling frequent ability use and powerful evasion builds. High investment can create nearly unstoppable combinations while saving on base Agility points.' },
        { name: 'Wings', tier: 'S', cost: 4, sprite: 'Wings_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Wings', review: 'Enables perfect flight at level 6, granting immunity to melee attacks on the surface and guaranteed escape routes. Significant boosts to Sprint, Charge, and Jump abilities. Crucial reputation bonus with birds and winged mammals provides safety from dangerous creatures. Though limited to above-ground use, the combined mobility and diplomatic advantages make it exceptional.' },
        { name: 'Electrical Generation', tier: 'A', cost: 4, sprite: 'Electrical_generation_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Electrical_Generation', review: 'Provides electrical attacks and infinite charging for jacked artifacts. Uniquely scales with movement speed rather than cooldowns, making it powerful with quickness builds. While electrical damage can be inconsistent and may harm allies, the ability to power artifacts indefinitely provides lasting utility. Requires investment to maximize effectiveness.' },
        { name: 'Heightened Hearing', tier: 'A', cost: 2, sprite: 'Heightened_hearing_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Heightened_Hearing', review: 'Lets you detect enemies beyond walls with greater range as it levels. Though powerful for early warning at just 2 points, higher levels can disrupt auto-movement when distant threats are detected. Strong defensive tool that works well without heavy investment.' },
        { name: 'Heightened Quickness', tier: 'A', cost: 3, sprite: 'Heightened_quickness_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Heightened_Quickness', review: 'Essential mutation that gives vital quickness bonus, excellent even at level 1. Due to diminishing returns (+2 per level), best leveled to 6 for +25 quickness. Synergizes well with fast weapons and enables better combat/escape options.' },
        { name: 'Horns', tier: 'A', cost: 4, sprite: 'Horns_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Horns', review: 'Strong offensive mutation that provides high damage attacks with guaranteed hits on charge and severe bleeding effects. Functions as natural weapon with built-in AV but prevents helmet use. Best suited for strength-focused melee builds and synergizes exceptionally with Single Weapon Fighting.' },
        { name: 'Multiple Arms', tier: 'A', cost: 4, sprite: 'Multiple_arms_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Multiple_Arms', review: 'Provides two extra arms with moderate strike chance that scales poorly with levels. Shines even at level 1 through clever equipment combinations - can dual-wield two-handed weapons, pair with shields, or enhance short blade builds. Excellent with Multiweapon Fighting skills and offers versatile equipment slot advantages. True power comes from build strategy rather than mutation investment.' },
        { name: 'Sleep Gas Generation', tier: 'A', cost: 3, sprite: 'Sleep_gas_generation_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Sleep_Gas_Generation', review: 'Powerful crowd control that inflicts sleep on most biological enemies, providing significant combat advantages through attack bonuses and enemy penalties. Effective even without heavy investment and enables strong defensive zoning. Works well with other gas mutations but ineffective against robots.' },
        { name: 'Two-headed', tier: 'A', cost: 3, sprite: 'Twoheaded_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Two-headed', review: 'Reduces mental mutation cooldowns and provides resistance to mental effects. While not useful for physical builds, it excels with mental mutations by allowing multiple casts in one turn at high levels. Also provides extra equipment slots for stacking bonuses from special gear.' },
        { name: 'Burrowing Claws', tier: 'B', cost: 3, sprite: 'Burrowing_claws_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Burrowing_Claws', review: 'Offers built-in digging ability without needing tools and functions as natural short blades with uncapped penetration. Though capable of high damage with strength investment, mainly useful as unleveled utility for terrain manipulation. In the upcoming release you will be able to dig passages up or down when outside of combat, which is pretty useful.' },
        { name: 'Phasing', tier: 'B', cost: 4, sprite: 'Phasing_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Phasing', review: 'A powerful defensive mutation that lets you pass through walls and escape most threats, but scales poorly (only +1 turn per level). While it can be used as a panic button at level 1, its effectiveness is reduced by movement speed buffs since phase duration counts your turns only. Has good synergies with mental mutations which can be used while phased.' },
        { name: 'Photosynthetic Skin', tier: 'B', cost: 2, sprite: 'Photosynthetic_skin_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Photosynthetic_Skin', review: 'Provides similar quickness bonuses as Heightened Quickness plus regeneration speed, with added DV bonus in foliage. While powerful, has notable drawbacks: requires daylight/surface to maintain buffs, vulnerability to defoliant, and conflicts with cooking effects. Good faction reputation bonuses and only 2 points make it worthwhile despite limitations.' },
        { name: 'Regeneration', tier: 'B', cost: 4, sprite: 'Regeneration_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Regeneration', review: 'Automatically heals dismemberment, diseases, and other debuffs, making it excellent for beginners. While it becomes less essential as you learn to avoid these conditions (and sometimes even want to keep certain diseases for their benefits), it still provides useful combat regeneration. High utility for new players, but veterans often manage without it.' },
        { name: 'Adrenal Control', tier: 'C', cost: 4, sprite: 'Adrenal_control_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Adrenal_Control', review: 'Temporarily boosts physical mutation levels and provides a quickness increase. While limited by short duration (20 turns) and long cooldown, it can be effective with multiple physical mutations or Chimera builds. Expensive (4 points) for what it offers, but has situational utility.' },
        { name: 'Beak', tier: 'C', cost: 1, sprite: 'Beak_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Beak', review: 'A 1-point mutation that grants +1 Ego and a minor peck attack. While the peck and bird faction reputation are negligible benefits, the Ego boost aids with item prices and mental mutation requirements. Like many 1-point mutations, it\'s serviceable but competes with saving points for more impactful abilities.' },
        { name: 'Flaming Ray', tier: 'C', cost: 4, sprite: 'Flaming_ray_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Flaming_Ray', review: 'A ranged fire damage mutation with low cooldown but requires heavy investment to be effective. While it deals decent damage, it\'s outclassed by other elemental mutations like Corrosive Gas Generation, and its fire damage becomes less useful late-game. The corpse-burning drawback can be particularly problematic.' },
        { name: 'Freezing Ray', tier: 'C', cost: 5, sprite: 'Freezing_ray_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Freezing_Ray', review: 'A 5-point ranged mutation that provides freeze resistance and deals cold damage, though less than Flaming Ray. While its freezing effect is weak without heavy investment, the passive freeze resistance is valuable regardless of investment.' },
        { name: 'Night Vision', tier: 'C', cost: 1, sprite: 'Night_vision_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Night_Vision', review: 'A 1-point mutation that provides built-in light source from game start, freeing up hand slots and helping with certain enemy detection. While outclassed by floating glowspheres and quantum motes later, its low cost and early game utility justify the investment.' },
        { name: 'Spinnerets', tier: 'C', cost: 3, sprite: 'Spinnerets_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Spinnerets', review: 'Grants permanent immunity to web and liquid entanglement, and can create webs to slow enemies. While its combat utility is limited compared to Sprint, it enables profitable phase silk farming and provides decent tactical options for its 3-point cost.' },
        { name: 'Thick Fur', tier: 'C', cost: 1, sprite: 'Thick_fur_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Thick_Fur', review: 'Provides minor cold and heat resistance, plus reputation bonuses with apes, baboons, bears, and hedonists. While the reputation boost can help locate Oboroquoru\'s lair, its benefits are modest. At 1 point cost, it\'s an okay filler mutation.' },
        { name: 'Two-hearted', tier: 'C', cost: 3, sprite: 'Twohearted_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Two-hearted', review: 'Provides Toughness bonus and extended Sprint duration. While the Toughness boost helps survivability, the sprint benefit is outclassed by other mobility options. Becomes less essential as game knowledge improves.' },
        { name: 'Electromagnetic Pulse', tier: 'D', cost: 2, sprite: 'Electromagnetic_pulse_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Electromagnetic_Pulse', review: 'Requires heavy investment for decent range and duration, while only affecting robots and select enemies. Despite being effective against dangerous robots like Chrome Pyramids, it\'s completely outclassed by craftable EMP grenades from Tinker I skill.' },
        { name: 'Quills', tier: 'D', cost: 4, sprite: 'Quills_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Quills', review: 'A poorly designed defensive mutation that prevents armor use while providing minimal AV and melee reflection. Its offensive Quill Fling ability consumes quills and weakens your defenses, becoming useless mid-game. Viable early but quickly outclassed by Carapace.' },
        { name: 'Slime Glands', tier: 'D', cost: 1, sprite: 'Slime_glands_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Slime_Glands', review: 'Provides slimewalking to prevent slipping on liquids, and lets you spit slime to dilute dangerous liquids. The slime-spitting ability has very limited tactical use, making this 1-point mutation hard to justify even at its low cost.' },
        { name: 'Stinger (Confusing Venom)', tier: 'D', cost: 3, sprite: 'Stinger_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Stinger_(Confusing_Venom)', review: 'A natural weapon that can temporarily remove enemies from combat through confusion, but flashbang grenades serve the same purpose more effectively. Has weak damage with single penetration, requires investment to work reliably, and is useless against robots.' },
        { name: 'Stinger (Paralyzing Venom)', tier: 'D', cost: 4, sprite: 'Stinger_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Stinger_(Paralyzing_Venom)', review: 'Can paralyze non-robotic enemies for several turns, with potential for longer duration through Willpower investment. While potentially powerful for crowd control, it\'s completely outclassed by Sleep Gas Generation which achieves similar results more efficiently.' },
        { name: 'Stinger (Poisoning Venom)', tier: 'D', cost: 4, sprite: 'Stinger_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Stinger_(Poisoning_Venom)', review: 'A venom that deals significant damage over time, but requires specific tactics like hit-and-run or crowd control to be effective. Useless against robots (which often have high HP) and encourages a tedious playstyle. More limited than Corrosive Gas Generation while costing more points.' },
        { name: 'Metamorphosis', tier: 'S', cost: 4, sprite: 'Metamorphosis_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Metamorphosis', review: 'Touch any creature to wear its body, inheriting their level, attributes, anatomy, mutations, and skills while keeping your own Intelligence, Willpower, Ego, and inventory. Despite the in-game description, the level cap is not actually enforced, so you can wear a Crowsong, an esper, or even a legendary apex outright. XP earned in the borrowed body returns to your original on cancel, so it doubles as a parallel-progression engine. Cooldown shrinks with investment (500 → 25 rounds at level 20, then turns negative), and you can buy mutations or spend skill points in the new body for the duration of the run. Currently flagged prerelease, enable "Allow unfinished and prerelease content", but obtainable in-game right now via permanent Domination of a Crowsong.' },
      ],
    },
    {
      label: 'Mental',
      entries: [
        { name: 'Domination', tier: 'S', cost: 5, sprite: 'Domination_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Domination', review: 'Enables mind control of creatures with numerous powerful applications. Can create super-powered followers by allocating their level-up resources, steal from merchants safely, scout dangerous areas in expendable bodies, and even permanently transfer consciousness to stronger hosts. Though requiring careful management and high cost, offers unparalleled versatility and game-breaking potential when mastered.' },
        { name: 'Force Bubble', tier: 'S', cost: 4, sprite: 'Force_bubble_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Force_Bubble', review: 'Creates mobile protective barrier that blocks all attacks while allowing you to attack through it. Exceptional even at level 1, requiring no investment to be effective. Perfect panic button that guarantees survival and victory if you can eliminate threats during its duration. Main drawback is cooldown only starts after effect ends. More expensive but simpler to use than Force Wall.' },
        { name: 'Force Wall', tier: 'S', cost: 3, sprite: 'Force_wall_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Force_Wall', review: 'Creates configurable 9-tile barrier with incredible versatility. Excels at trapping enemies, blocking projectiles, and enabling safe escapes when combined with movement abilities. Lower cost and longer uptime than Force Bubble. Can achieve permanent coverage with proper timing. Superior defensive option that rewards creative play.' },
        { name: 'Precognition', tier: 'S', cost: 4, sprite: 'Precognition_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Precognition', review: 'Offers unparalleled utility by allowing you to set a "save state" and rewind to it, enabling risk-free experimentation and perfect optimization of critical outcomes like item rolls, mutation picks, and combat tactics. Highly versatile and scales with game knowledge.' },
        { name: 'Sunder Mind', tier: 'S', cost: 4, sprite: 'Sunder_mind_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Sunder_Mind', review: 'Powerful long-range mental attack that deals devastating damage to organic targets after 10-turn charge. Excellent when paired with defensive abilities or Phasing for safe execution. Requires significant Ego or mutation investment but reliably eliminates enemies lacking mental shields. Can prevent enemy Sunder Mind use. Main drawbacks are long cooldown and vulnerability to interruption.' },
        { name: 'Confusion', tier: 'A', cost: 4, sprite: 'Confusion_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Confusion', review: 'Group stunning effect that temporarily disables enemies and makes them more vulnerable to mental attacks. While cooldown and duration are limiting factors, works exceptionally well with other mental powers, especially Sunder Mind and Domination. Most valuable as a setup for mental-focused builds rather than on its own. Main risk is reflection from enemies with Mental Mirror' },
        { name: 'Light Manipulation', tier: 'A', cost: 4, sprite: 'Light_manipulation_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Light_Manipulation', review: 'Long-range energy attack with perfect accuracy and reliable damage output. Limited by slow charge regeneration and struggles against heavily armored targets. Works best as supplementary ranged option rather than primary damage source. Also provides light but depletes with use.' },
        { name: 'Teleportation', tier: 'A', cost: 5, sprite: 'Teleportation_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Teleportation', review: 'Premium escape tool that becomes extremely reliable at high levels, allowing retreat from almost any dangerous situation including being cornered or engulfed. While expensive and requiring heavy investment to reduce random placement, unmatched as a defensive option. Particularly valuable for mental-focused builds.' },
        { name: 'Clairvoyance', tier: 'B', cost: 2, sprite: 'Clairvoyance_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Clairvoyance', review: 'Two-point mutation that reveals map and entities through walls. Requires heavy investment to overcome initial poor radius, duration, and cooldown limitations. Extremely powerful when leveled, enabling ranged mental attacks and safe scouting. Essential synergy with Sunder Mind and Teleportation. Perfect tool for identifying threats before engagement.' },
        { name: 'Mental Mirror', tier: 'B', cost: 2, sprite: 'Mental_mirror_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Mental_Mirror', review: 'Provides significant mental armor and reflects mental attacks once before cooldown. While most mental threats can be avoided through faction relations, offers reliable protection against psychic hunters and is especially valuable for high-Glimmer builds. Only 2 points makes it cost-effective insurance.' },
        { name: 'Temporal Fugue', tier: 'B', cost: 5, sprite: 'Temporal_fugue_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Temporal_Fugue', review: 'Creates temporary clones that share your abilities and inventory. Incredibly powerful but requires careful build planning as clones will spam mutations, grenades, and ranged weapons recklessly. Most effective with focused melee builds. Can backfire catastrophically with certain item combinations High reward but needs experienced management.' },
        { name: 'Time Dilation', tier: 'B', cost: 4, sprite: 'Time_dilation_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Time_Dilation', review: 'Short-range mutation that significantly reduces enemy quickness, most effective in melee combat. While powerful for melee-focused builds and capable of crippling strong enemies, fixed duration and melee requirement limit versatility.' },
        { name: 'Beguiling', tier: 'C', cost: 5, sprite: 'Beguiling_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Beguiling', review: 'High-cost mutation for recruiting a single follower with bonus health. While followers are powerful allies, the mutation is outclassed by the Proselytize skill which offers similar benefits without angering failed targets. Can\'t affect robots or oozes, and lost followers mean lost investment. Hard to justify the 5-point cost when water rituals can recruit legendary creatures.' },
        { name: 'Burgeoning', tier: 'C', cost: 3, sprite: 'Burgeoning_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Burgeoning', review: 'Creates random hostile plants that can be powerful allies but equally dangerous to yourself. Higher levels spawn deadlier plants like Feral Lah (chain explosions) and Aloe Pyra (line of fire attacks). Low cooldown makes it strong offensively, but uncontrollable nature and friendly fire make it extremely risky without fire resistance.' },
        { name: 'Disintegration', tier: 'C', cost: 3, sprite: 'Disintegration_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Disintegration', review: 'Short-range explosive attack that deals massive damage to structures and enemies but inflicts self-exhaustion. While potent early game and good for demolition, outclassed by resonance grenades and risky due to leaving user vulnerable. Interesting synergy with Two-Headed to counter exhaustion.' },
        { name: 'Ego Projection', tier: 'C', cost: 4, sprite: 'Ego_projection_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Ego_Projection', review: 'Temporarily boosts physical stats based on your Ego score. While offering flexible attribute enhancements for emergency situations, especially Toughness for survival, the long cooldown and short duration limit its effectiveness. Most useful for hybrid builds with high Ego but not essential.' },
        { name: 'Sense Psychic', tier: 'C', cost: 1, sprite: 'Sense_psychic_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Sense_Psychic', review: 'One-point detection ability that reveals enemies with mental mutations through walls, including surprising targets like Chrome Pyramids and voiders. While more limited than Heightened Hearing or Clairvoyance, decent value for its minimal cost. Often overlooked but surprisingly useful for identifying psychic threats.' },
        { name: 'Stunning Force', tier: 'C', cost: 4, sprite: 'Stunning_force_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Stunning_Force', review: 'Area knockback attack that stuns enemies and can push terrain. While recently buffed to deal significant damage when enemies hit walls, suffers from short stun duration, limited range, and long cooldown. Can interrupt dangerous abilities like Sunder Mind but requires heavy investment to be effective.' },
        { name: 'Teleport Other', tier: 'C', cost: 2, sprite: 'Teleport_other_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Teleport_Other', review: 'Provides guaranteed enemy displacement at melee range. While more reliable than Space-Time Vortex, random destination makes it unpredictable as an escape tool. Low cost and synergy with Syphon Vim make it worthwhile when mutation points are tight. Better options exist for defense, but serviceable in emergencies.' },
        { name: 'Cryokinesis', tier: 'D', cost: 5, sprite: 'Cryokinesis_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Cryokinesis', review: 'Creates freezing zone that can immobilize enemies but requires heavy investment for minimal effect. While offering some crowd control, the high cost, limited duration, and risk of self-freezing make it extremely inefficient. Better options exist for both damage and control.' },
        { name: 'Kindle', tier: 'D', cost: 1, sprite: 'Kindle_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Kindle', review: 'One-point mutation that creates weak heat source with minimal chance to ignite enemies. Long cooldown, immobile light source, and unreliable heating make it nearly useless even for its minimal cost.' },
        { name: 'Mass Mind', tier: 'D', cost: 4, sprite: 'Mass_mind_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Mass_Mind', review: 'Emergency cooldown reset for mental abilities that comes with significant risks. While potentially lifesaving, generates dangerous Glimmer, attracts hostile Seekers, and can backfire if enemy espers steal your resets. Most valuable for deliberate Glimmer farming but unreliable for general gameplay.' },
        { name: 'Psychometry', tier: 'D', cost: 4, sprite: 'Psychometry_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Psychometry', review: 'Provides artifact identification, recipe learning, and security access but largely redundant with basic Intelligence and Tinkering skills. Main value is learning grenade/injector recipes at level 1, but this benefit can be obtained from eating sun-dried bananas. High cost and investment requirements for minimal unique benefits.' },
        { name: 'Pyrokinesis', tier: 'D', cost: 5, sprite: 'Pyrokinesis_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Pyrokinesis', review: 'Creates damaging fire zone that can ignite enemies but most walk away before significant damage. While able to stunlock intelligent enemies who try to extinguish themselves, the high cost and unreliable effect make it hard to justify. Minor utility for evaporating liquids.' },
        { name: 'Space-Time Vortex', tier: 'D', cost: 3, sprite: 'Spacetime_vortex_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Space-Time_Vortex', review: 'Creates random teleportation portals that can remove dangerous enemies but with significant unreliability. While potentially game-changing against late-game threats like Cherubim, the long cooldown, random placement, and risk of teleporting dangerous creatures or self-teleporting into lethal situations make it hard to justify.' },
        { name: 'Syphon Vim', tier: 'D', cost: 3, sprite: 'Syphon_vim_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Syphon_Vim', review: 'Melee-range life drain that damages enemies and heals you. While it can provide good sustain when built around and combines well with defensive mutations, the extremely long cooldown and need for close combat make it risky for mental builds. Synergizes with Phasing and Teleport Other but outclassed by other damage options.' },
        { name: 'Telepathy', tier: 'D', cost: 1, sprite: 'Telepathy_mutation.png', wiki: 'https://wiki.cavesofqud.com/wiki/Telepathy', review: 'One-point mutation that enables communication with creatures and immunity to trade penalties from glotrot. While theoretically useful for commanding followers or detecting invisible enemies, rarely provides meaningful value in practice. Nearly forgettable in actual gameplay.' },
      ],
    },
  ],
};

export const CYBERNETICS: TierList = {
  slug: 'cybernetics',
  title: 'Cybernetics',
  entries: [
        { name: 'Cathedra with ruby tracery', tier: 'S', cost: 12, slot: 'Back', sprite: 'Cathedra_with_ruby_tracery_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Cathedra_with_ruby_tracery', review: 'All Cathedra provide powerful baseline benefits: +100 carrying capacity, +100 move speed, +50 HP, +3 Ego, and perfect flight, with compute power enhancing flight level, cooldown, and ability. The Ruby version generates a pyrokinesis burst, similar to the Pyrokinesis mental mutation, centered on you for AOE fire damage. The Ruby Tracery variant further enhances the effect with a larger burst radius and increased duration, making it a strong offensive choice for combat-heavy builds. Despite losing the back equipment slot and being uninstallable, its potent damage potential makes it a worthwhile pick for aggressive or AOE-oriented playstyles.' },
        { name: 'Cathedra with sapphire tracery', tier: 'S', cost: 12, slot: 'Back', sprite: 'Cathedra_with_sapphire_tracery_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Cathedra_with_sapphire_tracery', review: 'All Cathedra provide powerful baseline benefits: +100 carrying capacity, +100 move speed, +50 HP, +3 Ego, and perfect flight, with compute power enhancing flight level, cooldown, and ability. The Sapphire version invokes a concussive blast, knocking enemies back and stunning them, similar to the Stunning Force mental mutation. it is a great choice for crowd control in melee-heavy or swarm scenarios. Despite losing the back equipment slot and the inability to uninstall, its utility in controlling the battlefield makes it a compelling option for many builds.' },
        { name: 'Giant hands', tier: 'S', cost: 3, slot: 'Hands', sprite: 'Giant_hands_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Giant_hands', review: 'Enables two-handed weapons to be wielded in one hand, massively boosting versatility and damage potential for multiweapon builds. Synergizes exceptionally well with Helping Hands and Gun Rack, allowing melee or ranged builds to leverage multiple powerful weapons simultaneously. A top-tier cybernetic for Strength-centered characters but irrelevant for pistol or vibro weapon builds.' },
        { name: 'Gun rack', tier: 'S', cost: 6, slot: 'Back', sprite: 'Gun_rack_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Gun_rack', review: 'Adds two ranged weapon slots, drastically increasing damage potential by allowing additional rifles or pistols. Synergizes with Giant Hands to wield up to four rifles and can be combined with magnetized guns for further boosts. While it replaces the back equipment slot, its power to double or even triple ranged DPS makes it a cornerstone cybernetic for ranged builds.' },
        { name: 'High-fidelity matter recompositer', tier: 'S', cost: 8, slot: 'Body', sprite: 'Highfidelity_matter_recompositer_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/High-fidelity_matter_recompositer', review: 'Instantly teleports you to a chosen explored tile with a base cooldown of 50 turns, making it one of the most reliable escape tools available. The cooldown can be reduced with compute power and Willpower down to a minimum of 5 turns, further bolstering its utility. Unlike its lower-tier counterpart, this cybernetic eliminates randomness, ensuring precision in repositioning during critical moments. While its primary use is as a defensive escape option, those prioritizing offensive builds may prefer cybernetics that boost damage potential.' },
        { name: 'Optical multiscanner', tier: 'S', cost: 8, slot: 'Face', sprite: 'Optical_multiscanner_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Optical_multiscanner', review: 'Combines the functionality of a bioscanner and technoscanner with added features like structural scanning and automatic staircase detection. While structural scanning is of limited use, the staircase display is an invaluable feature for navigation and exploration, especially in sprawling or maze-like zones. Although its high cost and face slot requirement make it an investment, the comprehensive utility it provides makes it a worthwhile addition for builds focused on exploration and information gathering.' },
        { name: 'Penetrating radar', tier: 'S', cost: 6, slot: 'Body, Back, Head, Face, Arm', sprite: 'Penetrating_radar_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Penetrating_radar', review: 'Reveals all tiles within range, bypassing walls and obstructions, including hidden enemies and hazards like galgals or roots. Its flexibility in slot placement makes it adaptable to most builds, and compute power boosts extend its range for even greater utility. A highly valuable tool for exploration, navigation, and avoiding ambushes.' },
        { name: 'Stasis projector', tier: 'S', cost: 6, slot: 'Head, Arm, Hands, Body, Back', sprite: 'Stasis_projector_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Stasis_projector', review: 'Creates six stasis fields for 5 rounds, offering strong crowd-control utility. The ability to place fields strategically makes it versatile, allowing for defensive uses like escaping enemies or controlling multiple threats, as well as offensive uses to immobilize fleeing targets. Its flexibility in slot placement adds to its appeal.' },
        { name: 'Biodynamic power plant', tier: 'A', cost: 6, slot: 'Body', sprite: 'Biodynamic_power_plant_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Biodynamic_power_plant', review: 'Generates 5,000 units of charge per turn, offering an unparalleled solution to power supply for builds centered around jacked artifacts or multi-energy weapon setups. This eliminates the resource constraints of energy-intensive gear, making it ideal for Tinker II builds leveraging advanced artifacts. However, without jacked equipment or a focus on Tinkering, the cybernetic provides no utility, making its high cost situational.' },
        { name: 'Bionic arm', tier: 'A', cost: 3, slot: 'Arm', sprite: 'Bionic_arm_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Bionic_arm', review: 'Provides a +2 Strength bonus per arm, making it an excellent choice for melee builds or any characters reliant on Strength-based mechanics. Unlike many stat-boosting cybernetics, it takes up an arm slot, which is less competitive and allows synergy with other powerful upgrades like Carbide Hand Bones. Stacking two Bionic Arms grants a substantial +4 Strength boost, offering significant melee and carry capacity gains.' },
        { name: 'Carbide hand bones', tier: 'A', cost: 2, slot: 'Hands', sprite: 'Carbide_hand_bones_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Carbide_hand_bones', review: 'Boosts unarmed damage to 2d3, offering a significant early- to mid-game power spike for melee builds. Functions as a cudgel-class weapon with no penetration value (PV) cap and scales well with high Strength and Cudgel skills. While it eventually falls behind high-tier melee weapons, its performance in the early game and compatibility with strength-based unarmed builds make it a standout option.' },
        { name: 'Cathedra with black opal tracery', tier: 'A', cost: 12, slot: 'Back', sprite: 'Cathedra_with_black_opal_tracery_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Cathedra_with_black_opal_tracery', review: 'All Cathedra provide powerful baseline benefits: +100 carrying capacity, +100 move speed, +50 HP, +3 Ego, and perfect flight, with compute power enhancing flight level, cooldown, and ability. The Black Opal version\'s unique ability allows teleportation to a random location in Qud. While the ability offers potential escape utility, it lacks reliability since the destination is random, potentially placing you in even more dangerous situations. Given its inability to be uninstalled, paired with the high opportunity cost of losing the back equipment slot, it\'s difficult to recommend over more controlled or useful Cathedra variants.' },
        { name: 'Cathedra with white opal tracery', tier: 'A', cost: 12, slot: 'Back', sprite: 'Cathedra_with_white_opal_tracery_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Cathedra_with_white_opal_tracery', review: 'All Cathedra provide powerful baseline benefits: +100 carrying capacity, +100 move speed, +50 HP, +3 Ego, and perfect flight, with compute power enhancing flight level, cooldown, and ability. The White Opal version only releases a burst of glitter dust around yourself, which has little combat value. Given the Cathedra cannot be uninstalled once equipped, hold off on installing this variant so you can pick a stronger tracery later.' },
        { name: 'Custom visage', tier: 'A', cost: 3, slot: 'Face', sprite: 'Custom_visage_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Custom_visage', review: 'Grants +300 reputation with a chosen faction, easily shifting even hostile factions to neutrality. This makes it invaluable for smoothing relations with dangerous groups like robots or for gaining specific perks through faction alignment (e.g., Seekers for mental mutations). Best used as a temporary installation while building natural reputation or resolving immediate faction conflicts. Its utility fades once reputation priorities are stabilized, but its flexibility and impact in the mid-game are significant.' },
        { name: 'Equipment rack', tier: 'A', cost: 3, slot: 'Body', sprite: 'Equipment_rack_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Equipment_rack', review: 'Grants an additional back equipment slot, offering immense flexibility and synergy with certain loadouts. It enables stacking two cloaks, banners, or other beneficial back items, doubling their effects. Particularly powerful when combined with specialized equipment like Helping Hands, allowing for builds that use multiple limbs and fully leverage the Multiweapon Fighting skill.' },
        { name: 'Fullerite hand bones', tier: 'A', cost: 4, slot: 'Hands', sprite: 'Fullerite_hand_bones_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Fullerite_hand_bones', review: 'A direct upgrade to Carbide Hand Bones, boosting unarmed damage to 2d4+1, equivalent to a one-handed fullerite maul. These are ideal for melee-focused builds looking to maximize unarmed damage output, particularly with Cudgel skills due to the chance to stun.' },
        { name: 'Medassist module', tier: 'A', cost: 3, slot: 'Body, Back, Arm', sprite: 'Medassist_module_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Medassist_module', review: 'Automatically applies injectors like salve tonics when health drops below a set threshold with no action cost, making it an excellent safety tool. Its utility is significant for new players or in scenarios where effects like stun or sleep could prevent timely healing. While experienced players may find manual injector use preferable, its ability to mitigate critical situations adds lasting value, particularly for builds prioritizing survivability.' },
        { name: 'Motorized treads', tier: 'A', cost: 4, slot: 'Feet', sprite: 'Motorized_treads_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Motorized_treads', review: 'Grants +150 move speed and significant bonuses to saves (e.g., versus prone, restraint, and knockdown), making it excellent for ranged builds and versatile mobility. However, it permanently replaces your legs, restricting you to tread guards for footgear, which provide less AV and DV compared to top-tier options. While these trade-offs are significant, the maneuverability and survivability make it a standout option. Choose carefully, this cybernetic cannot be uninstalled.' },
        { name: 'Night vision', tier: 'A', cost: 2, slot: 'Face', sprite: 'Night_vision_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Night_vision_(implant)', review: 'Grants unmatched vision range, far exceeding any standard light source, including floating glowspheres or night-vision goggles. This makes it invaluable for both exploration and combat, particularly for dual-wielding or two-handed builds that need to keep their hands free. Its superior vision removes the need for light-emitting gear, offering seamless flexibility.' },
        { name: 'Optical technoscanner', tier: 'A', cost: 1, slot: 'Face', sprite: 'Optical_technoscanner_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Optical_technoscanner', review: 'Scans robots for health data and automatically identifies artifacts, including items in merchant inventories. This makes it incredibly useful for managing resources and purchasing the right gear without wasting drams. While eventually outclassed by the telemetric visor, its artifact-identification ability is invaluable for the mid-game. A strong choice for utility until late-game upgrades become available.' },
        { name: 'Palladium electrodeposits', tier: 'A', cost: 3, slot: 'Head, Body, Back, Arm', sprite: 'Palladium_electrodeposits_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Palladium_electrodeposits', review: 'Provides 20 units of compute power that enhance certain cybernetics and items like Cathedra, High-Fidelity Matter Recompositor, Inflatable Axons, Penetrating Radar, and Point-Defense Drone by 20% per unit. While stacking multiple electrodeposits is possible, the improvements are rarely significant enough to justify giving up multiple competitive slots.' },
        { name: 'Rapid release finger flexors', tier: 'A', cost: 2, slot: 'Hands', sprite: 'Rapid_release_finger_flexors_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Rapid_release_finger_flexors', review: 'Increases Pistol firing speed significantly, stacking multiplicatively with skills like Fastest Gun in the Rust, making it essential for Pistol-focused builds. At its peak, it enables rapid volleys of shots, melting enemies before they can react, especially when combined with quickness buffs or Gun Rack cybernetics. While its benefits are immense for dedicated Pistol users, it offers no value to non-Pistol builds or those using Pistols only as a secondary tool.' },
        { name: 'Social coprocessor', tier: 'A', cost: 8, slot: 'Head', sprite: 'Social_coprocessor_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Social_coprocessor', review: 'Boosts reputation management by adding +25 reputation to water rituals (stacking with Tactful), reducing reputation costs for rewards by 20%, and allowing an additional Proselytized follower. Best suited for ally-focused builds that specialize in creating armies of followers. its high cost and situational focus make it less appealing for combat-heavy or solo-driven playstyles.' },
        { name: 'Stabilizer arm locks', tier: 'A', cost: 2, slot: 'Arm', sprite: 'Stabilizer_arm_locks_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Stabilizer_arm_locks', review: 'Provides a significant stacking boost to ranged weapon accuracy, making it invaluable for early- and mid-game ranged builds or any character relying on firearms. Particularly effective when paired with high-accuracy weapons like sniper rifles, it drastically reduces the chance of missing, even at long distances. While its impact diminishes as your raw accuracy and weapon precision improve in the late game, it\'s an excellent, versatile early pick that fits into nearly any build for consistent ranged performance.' },
        { name: 'Stasis entangler', tier: 'A', cost: 8, slot: 'Feet, Back, Body', sprite: 'Stasis_entangler_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Stasis_entangler', review: 'A powerful activated tool that places all enemies on screen into stasis for 15 rounds, allowing you to control a chaotic situation by effectively pausing all but one chosen creature. It\'s an exceptional crowd-control utility, granting you time to escape, strategize, or take on a single target in relative isolation. While it shares similarities with the Stasis Projector, its targeted exclusion mechanic allows for better precision in managing combat engagements. The cooldown (200 turns) and cost are steep, but its tactical flexibility makes it an excellent option for high-risk zones or overwhelming multi-enemy fights.' },
        { name: 'Transparent skin', tier: 'A', cost: 3, slot: 'Body, Back', sprite: 'Transparent_skin_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Transparent_skin', review: 'Grants +3 DV, making it an incremental upgrade over Translucent Skin for just 1 additional license point. This works well for boosting dodge-focused builds, particularly in the early-to-mid-game, and is an easily justified upgrade if you\'re already using Translucent Skin. However, as high-DV builds lose some effectiveness in the late game, it becomes replaceable as better options become available for body or back slots.' },
        { name: 'Air current microsensor', tier: 'B', cost: 2, slot: 'Body, Head', sprite: 'Air_current_microsensor_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Air_current_microsensor', review: 'Reveals staircases and level transitions, making exploration faster and more efficient. Best used in the head slot as a convenience tool, though it competes with stronger late-game options.' },
        { name: 'Anchor spikes', tier: 'B', cost: 2, slot: 'Feet', sprite: 'Anchor_spikes_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Anchor_spikes', review: 'Prevents forced movement effects such as Slam, Hook and Drag, Blast Cannons, and conveyor belts while ensuring stability on slippery surfaces like slime. Its utility is especially notable in late-game or Slam-heavy encounters. However, it doesn\'t stop being knocked prone, which limits its effectiveness. While niche, it excels in specific scenarios and offers unique control in certain areas, making it a solid, situational pick depending on the threats you face.' },
        { name: 'Communications interlock', tier: 'B', cost: 2, slot: 'Hands, Feet, Body, Back, Face, Arm, Head', sprite: 'Communications_interlock_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Communications_interlock', review: 'Enhances rebuking robots, significantly increasing success rates for turning hostile machines into allies. Flexible in slot placement and synergizes well with robot-heavy zones. While useful for robot-focused strategies, its limited scope compared to more versatile defensive tools keeps it from being universally appealing.' },
        { name: 'Crysteel hand bones', tier: 'B', cost: 8, slot: 'Hands', sprite: 'Crysteel_hand_bones_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Crysteel_hand_bones', review: 'Delivers 3d4 unarmed damage, slightly outperforming the crysteel mace while featuring uncapped penetration scaling. However, the steep cost and stiff competition from late-game options like zetachrome weapons, flawless crysteel cudgels, and the Fist of the Ape God makes it suboptimal. Uncapped PV offers theoretical scaling with extremely high Strength, but practical scenarios where it surpasses other high-end weaponry are rare.' },
        { name: 'Dermal plating', tier: 'B', cost: 3, slot: 'Body, Head, Back', sprite: 'Dermal_plating_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Dermal_plating', review: 'Provides +1 AV, giving a modest boost to physical defense. Though simple, it\'s a useful early-to-mid-game option for improving survivability, especially when body or back slots are unoccupied. Best used as a placeholder until better options are available.' },
        { name: 'Electromagnetic sensor', tier: 'B', cost: 1, slot: 'Head, Face, Back, Body, Feet, Arm, Hands', sprite: 'Electromagnetic_sensor_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Electromagnetic_sensor', review: 'Detects nearby robots, helping identify threats like turrets or chrome pyramids early. Its low cost and flexibility to fit any slot make it a strong filler cybernetic for the early game, but its utility fades mid to late game as robotic threats become easier to recognize or avoid.' },
        { name: 'Force modulator', tier: 'B', cost: 1, slot: 'Hands, Feet, Body, Back, Face, Arm, Head', sprite: 'Force_modulator_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Force_modulator', review: 'Allows you to pass through forcefields, granting immunity to stasis fields and protection from being trapped by force wall or force bubble effects. Rarely situational but invaluable when dealing with enemies like chrome pyramids or force wall-users. Useful for strategic escapes or niche tactics, yet its limited applicability makes it best kept uninstalled until needed.' },
        { name: 'Grafted mirror arm', tier: 'B', cost: 5, slot: 'Arm', sprite: 'Grafted_mirror_arm_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Grafted_mirror_arm', review: 'Grants an additional throw slot per installation, allowing simultaneous throws across all slots. This boosts the effectiveness of grenade builds or geomagnetic disc strategies by enabling multi-target or burst damage. When paired with the Precision Force Lathe, it shines in dagger-throwing builds, rapidly deploying vibro-force knives for high single-target damage. However, its synergy comes with the cost of multiple cybernetic slots, making it difficult to fit in alongside other powerful options like Penetrating Radar or defensive tools.' },
        { name: 'Magnetic core', tier: 'B', cost: 4, slot: 'Body', sprite: 'Magnetic_core_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Magnetic_core', review: 'Grants an additional Floating Nearby equipment slot. Useful for magnetized items that can be used in the floating nearby slot, however, those come late in the game. You can also equip Chiral rings, however this cybernetic is just not very useful in general.' },
        { name: 'Onboard recoiler', tier: 'B', cost: 4, slot: 'Hands, Feet, Body, Back, Face, Arm, Head', sprite: 'Onboard_recoiler_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Onboard_recoiler', review: 'Functions as a reprogrammable recoiler that never consumes power, providing reliable teleportation back to set locations. Extremely useful for convenience and establishing a base or fallback point, especially in the late game. However, its utility is somewhat redundant if you already have portable reprogrammable recoilers and sufficient power cells.' },
        { name: 'Pentaceps', tier: 'B', cost: 2, slot: 'Feet', sprite: 'Pentaceps_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Pentaceps', review: 'Boosts Charge range significantly, providing excellent gap-closing and mobility for melee builds. Its low cost and strong synergy with charge-focused playstyles or melee weapons make it an exceptional pick for most of the game. While less useful for ranged builds, it offers unmatched bursts of aggression and feels fantastic in action. Pairs particularly well with cybernetics and skills that amplify melee combat effectiveness.' },
        { name: 'Phase-adaptive scope', tier: 'B', cost: 4, slot: 'Back', sprite: 'Phaseadaptive_scope_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Phase-adaptive_scope', review: 'Allows firing through walls, offering incredible tactical advantages in confined spaces like caves or dense environments. However, it relies heavily on pairing with support tools like Penetrating Radar or Night-Sight Interpolators to detect enemies, which adds to the setup cost. While undeniably powerful when properly utilized, it competes with other high-impact back-slot cybernetics like Gun Rack or Cathedra.' },
        { name: 'Precision force lathe', tier: 'B', cost: 4, slot: 'Head, Arm, Body, Back', sprite: 'Precision_force_lathe_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Precision_force_lathe', review: 'Generates force knives (vibro weapons with a 1d8 damage) to fill empty hand and thrown weapon slots, offering a constant supply of armor-bypassing weaponry. It synergizes particularly well with Grafted Mirror Arms cybernetic, Multiweapon Fighting builds, and Short Blade skills like Flurry or Rejoinder, making it both thematic and effective.' },
        { name: 'Reactive cranial plating', tier: 'B', cost: 2, slot: 'Head', sprite: 'Reactive_cranial_plating_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Reactive_cranial_plating', review: 'Grants immunity to stun and daze effects, offering excellent protection against cudgel-based enemies like apes and galgals, which can otherwise chain-disable you and leave you vulnerable. While it\'s more impactful for melee or high-DV builds that rely on mobility, it\'s less necessary for ranged builds or those with limited contact with cudgel users. Shake it Off provides a weaker alternative, but this cybernetic\'s reliability makes it a strong choice for melee-focused or general-purpose survivability.' },
        { name: 'Tibular hydrojets', tier: 'B', cost: 1, slot: 'Feet', sprite: 'Tibular_hydrojets_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Tibular_hydrojets', review: 'Improves swimming speed, making it easier to navigate water-heavy zones such as Bethesda Susa and Golgotha. While it lacks general utility and only affects aquatic movement, its low cost and situational effectiveness against waterborne threats like madpoles make it a decent choice early on. Best used as a temporary upgrade when exploring areas filled with dangerous liquids.' },
        { name: 'Translucent skin', tier: 'B', cost: 2, slot: 'Body, Back', sprite: 'Translucent_skin_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Translucent_skin', review: 'Grants +2 DV, a strong early-game defensive boost with excellent synergy for DV-focused or short blade builds, particularly after acquiring Rejoinder. It pairs well with setups balancing heavy armor or shields that reduce DV, mitigating penalties while retaining durability. However, its value diminishes later in the game as higher-tier gear naturally balances AV and DV. A solid pick early on with strong utility for builds prioritizing dodge-based defense or melee counters.' },
        { name: 'Bionic hands', tier: 'C', cost: 3, slot: 'Hands', sprite: 'Bionic_hands_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Bionic_hands', review: 'Grants +2 Agility, translating to minor bonuses like +1 to hit and +1 DV. While helpful early game or for builds relying on Agility, it struggles to compete with more impactful hand-slot cybernetics like Rapid Release Finger Flexors, Carbide Hand Bones, or Giant Hands. By mid-game, its benefits are too marginal to justify the slot, particularly for combat-heavy builds.' },
        { name: 'Bionic heart', tier: 'C', cost: 3, slot: 'Body', sprite: 'Bionic_heart_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Bionic_heart', review: 'Provides +2 Toughness, adding bonus hitpoints equal to 2 × your level and satisfying any skill prerequisites using base Toughness. While the scaling HP benefits are decent, it falls short of being impactful due to its competition for the body slot, which hosts stronger utility or combat-enhancing cybernetics. Useful early for survivability or skill requirements.' },
        { name: 'Dopamine synth', tier: 'C', cost: 3, slot: 'Head', sprite: 'Dopamine_synth_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Dopamine_synth', review: 'Provides +2 Willpower, potentially reducing cooldowns and improving abilities reliant on mental stats. While Willpower is a strong attribute, allocating a head slot to this cybernetic is situational. Best for specialized Willpower-focused builds rather than general-purpose use.' },
        { name: 'Holographic visage', tier: 'C', cost: 6, slot: 'Face', sprite: 'Holographic_visage_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Holographic_visage', review: 'Grants +200 reputation with a faction of your choice at will, providing flexibility to smooth over relations or gain temporary benefits. However, the reputation boost is often too small to make a significant impact on its own, especially for hostile factions. Its face slot competition, situational value, and limited long-term utility make it a niche pick at best.' },
        { name: 'Inflatable axons', tier: 'C', cost: 2, slot: 'Head', sprite: 'Inflatable_axons_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Inflatable_axons', review: 'Provides +40 quickness for 10 rounds, granting 3-4 additional actions in a fight depending on its length, followed by a -10 quickness penalty for 10 rounds. Scales with enhanced compute power to increase both duration and bonus, making it situationally powerful for taking down tough enemies quickly. However, the quickness penalty can backfire if the enemy survives the boosted phase, leaving you vulnerable. Best used in burst damage builds or for rapidly finishing high-threat encounters, but weaker for prolonged combat.' },
        { name: 'Intravenous port', tier: 'C', cost: 3, slot: 'Hands, Feet, Body, Back, Face, Arm, Head', sprite: 'Intravenous_port_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Intravenous_port', review: 'Doubles the duration of tonic effects, but most tonics don\'t justify the slot usage due to their already short duration and situational benefits. It shines in niche cases with items like sphynx salt injectors for extended Precognition, enabling advanced strategies like RNG manipulation. However, for general healing or combat tonics, the default duration is sufficient, and there are far better cybernetics for long-term utility.' },
        { name: 'Micromanipulator array', tier: 'C', cost: 5, slot: 'Hands', sprite: 'Micromanipulator_array_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Micromanipulator_array', review: 'Grants bonuses to artifact identification, increased bit recovery during disassembly, and in-combat tinkering or repairs. While these features can be situationally useful - particularly for crafting builds or emergency repairs - their impact is limited as preparation and resource management reduce their necessity. At 5 points, with stiff competition for the hands slot, it struggles to justify inclusion in most builds beyond the early game.' },
        { name: 'Navigation system', tier: 'C', cost: 1, slot: 'Head, Arm, Hands, Body, Back', sprite: 'Navigation_system_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Navigation_system', review: 'Functions as a built-in compass bracelet, providing a 30% chance to avoid getting lost in ruins while freeing up the arm equipment slot. Its low cost, flexibility across multiple slots, and convenience make it a useful early-game option. However, it quickly loses appeal as more impactful cybernetics become available, and its advantages do not stack with other navigation tools like compass bracelets.' },
        { name: 'Nocturnal apex', tier: 'C', cost: 2, slot: 'Head', sprite: 'Nocturnal_apex_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Nocturnal_apex', review: 'Provides minor bonuses based on the time of day. During the day, natural healing is increased by 10%, which is negligible. At night, users gain a one-time activation of Prowl, granting +6 Agility (equating to +3 DV) and +10 movement speed for 100 rounds. While the temporary Agility boost can help in clutch situations, the once-per-night limitation and short duration make it situational at best. Limited utility and strong competition for useful slots make this cybernetic a below-average pick.' },
        { name: 'Parabolic muscular subroutine', tier: 'C', cost: 2, slot: 'Arm', sprite: 'Parabolic_muscular_subroutine_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Parabolic_muscular_subroutine', review: 'Increases throwing range by 2 tiles and ensures perfect accuracy within throwing range. While theoretically useful for grenade or throwable-focused builds, the benefits are largely redundant if you already have the Deft Throwing skill. Throwing builds are notoriously difficult to make effective, and grenades rarely require pinpoint accuracy. Its low cost and availability in the arm slot make it an acceptable filler, but it\'s far from a strong or broadly applicable choice.' },
        { name: 'Anomaly fumigator', tier: 'D', cost: 3, slot: 'Hands, Feet, Body, Back, Face, Arm, Head', sprite: 'Anomaly_fumigator_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Anomaly_fumigator', review: 'Releases normality gas, which can negate mental abilities and disable certain anomalies like force walls and bubbles. While situationally useful, alternatives such as normality grenades or nulling-mod weapons provide similar functionality without consuming a valuable cybernetic slot. Its utility is further limited by the rare occurrence of Ptoh\'s servants and its potential to backfire by disabling your own abilities.' },
        { name: 'Beautiful visage', tier: 'D', cost: 3, slot: 'Face', sprite: 'Beautiful_visage_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Beautiful_visage', review: 'Provides +2 Ego at the cost of 3 license points, making it a slightly stronger but far less efficient version of Cherubic Visage. While it offers better bonuses, Ego remains a marginal stat outside of very specific uses, such as bartering. The high cost and competition for the face slot make it an underwhelming choice compared to alternatives.' },
        { name: 'Bionic liver', tier: 'D', cost: 3, slot: 'Body', sprite: 'Bionic_liver_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Bionic_liver', review: 'Grants immunity to poison and disease, but its utility is highly situational, primarily relevant for Golgotha, where diseases are more of a concern. Outside of that, poison damage is rare and becomes even less prominent as the game progresses.' },
        { name: 'Cherubic visage', tier: 'D', cost: 1, slot: 'Face', sprite: 'Cherubic_visage_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Cherubic_visage', review: 'Grants +1 Ego for minimal cost, making it a cheap and accessible early-game cybernetic for the face slot. Useful while no better options are available but offers diminishing returns as you progress and acquire stronger face-slot upgrades. Its simplicity and low impact limit its long-term value.' },
        { name: 'Dermal insulation', tier: 'D', cost: 2, slot: 'Body, Head, Back', sprite: 'Dermal_insulation_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Dermal_insulation', review: 'Provides a 6% reduction to heat, cold, electric, and acid damage, offering small resistance against elemental attacks. Freezing resistance is its most useful feature, but the overall impact is negligible, and it competes with far more impactful cybernetics for key slots. Its utility is limited to the early game, where low incoming elemental damage makes the small percentage reduction somewhat useful.' },
        { name: 'Fire suppression system', tier: 'D', cost: 2, slot: 'Head, Body, Back', sprite: 'Fire_suppression_system_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Fire_suppression_system', review: 'Releases gel when you take fire damage to extinguish flames. However, fire is rarely a significant threat, and carrying gel or other protective measures is a better alternative. Its inability to reliably extinguish flames or protect gear further reduces its value. Competes with more effective cybernetics for slots, making it a poor choice for almost any build.' },
        { name: 'Grounding shunts', tier: 'D', cost: 2, slot: 'Feet', sprite: 'Grounding_shunts_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Grounding_shunts', review: 'Provides 50% resistance to electrical damage, but the rarity of electrical attacks in most encounters limits its usefulness. While situationally helpful against specific threats like quatravolt gliders or electrical cherubs, it\'s overshadowed by rubbergum injectors, which offer complete immunity and additional effects. The valuable feet slot is better served by cybernetics with more versatile applications.' },
        { name: 'High-grade dermal insulation', tier: 'D', cost: 3, slot: 'Body, Head, Back', sprite: 'Highgrade_dermal_insulation_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/High-grade_dermal_insulation', review: 'Provides 9% resistance to heat, cold, electric, and acid damage. While an improvement over regular Dermal Insulation, the marginal increase isn\'t impactful enough to matter in most scenarios. Elemental damage types are either rare or not sufficiently threatening to justify using a competitive slot for such a small mitigation increase.' },
        { name: 'Hyper-elastic ankle tendons', tier: 'D', cost: 2, slot: 'Feet', sprite: 'Hyperelastic_ankle_tendons_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Hyper-elastic_ankle_tendons', review: 'Grants +6 movement speed, which is modest and situational at best. While it can help with escaping encounters or closing gaps, it pales in comparison to more impactful feet-slot options. The boost is underwhelming long-term since Sprint or other movement-enhancing abilities can achieve similar results. A cheap but largely uninspiring choice.' },
        { name: 'Matter recompositer', tier: 'D', cost: 3, slot: 'Body', sprite: 'Matter_recompositer_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Matter_recompositer', review: 'Teleports you to a random explored tile, making it a largely unreliable escape tool. Its lack of control over destination means you risk ending up in equally or more dangerous situations, such as hazardous liquids or near enemies. While it has potential as a panic button, the unpredictability and long cooldown limit its usefulness. Better alternatives exist for tactical repositioning or escapes.' },
        { name: 'Optical bioscanner', tier: 'D', cost: 1, slot: 'Face', sprite: 'Optical_bioscanner_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Optical_bioscanner', review: 'Displays exact health values for biological targets, useful for gauging enemy strength or determining when a foe is close to death. While helpful for new players learning enemy capabilities, its utility fades quickly with game experience, as descriptive health indicators become sufficient. As a face-slot cybernetic, it is easily replaced by more impactful options, and its effect can also be replicated by the bioscanning bracelet.' },
        { name: 'Phase harmonic modulator', tier: 'D', cost: 2, slot: 'Hands, Feet, Body, Back, Face, Arm, Head', sprite: 'Phase_harmonic_modulator_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Phase_harmonic_modulator', review: 'Allows interaction with phased creatures and objects, but its practical utility is extremely limited. Few enemies, like astral tabbies, are phased in regular encounters, and they rarely pose a significant threat. While conceptually intriguing, its effect is situational at best, and becomes counterproductive if you gain the Phasing ability yourself, as it would allow enemies to interact with you while phased.' },
        { name: 'Pneumatic pistons', tier: 'D', cost: 2, slot: 'Feet', sprite: 'Pneumatic_pistons_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Pneumatic_pistons', review: 'Provides the ability to Jump, allowing movement over a short distance in any direction. While this may occasionally help with positioning or escaping, it lacks the combat utility, range, and overall versatility of Charge, as provided by Pentaceps. With no damage component, no skill-based synergies, and a high cooldown, Pneumatic Pistons are outclassed in almost every scenario, making them a poor choice compared to alternative mobility options.' },
        { name: 'Reactive trauma plate', tier: 'D', cost: 4, slot: 'Body', sprite: 'Reactive_trauma_plate_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Reactive_trauma_plate', review: 'Provides a one-time effect that either prevents death or cuts a single hit\'s damage in half before being permanently destroyed. While it can save you in rare high-damage scenarios, such as massive explosions or nukes, the permanent loss of the slot and the single-use nature make it impractical for most builds.' },
        { name: 'Schemasoft', tier: 'D', slot: 'Head', sprite: 'Schemasoft_identified.png', review: 'Schemasoft variants (Low-tier, Mid-tier, and High-tier) grant Tinkering recipes from a single category but lack access to mod schematics, making them suboptimal compared to acquiring recipes from data disks or investing in Tinkering skills. Low-tier and Mid-tier variants are situationally useful early on for limited artifacts (e.g., grenades or utilities) but are quickly outclassed, especially as critical recipes become easier to find. High-tier can help bypass Tinker III\'s Intelligence requirement, providing access to powerful artifacts, but it consumes your head slot, is destroyed upon removal, and is only practical for batch crafting before uninstalling.' },
        { name: 'Security interlock', tier: 'D', cost: 3, slot: 'Hands, Feet, Body, Back, Face, Arm, Head', sprite: 'Security_interlock_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Security_interlock', review: 'Grants the ability to unlock doors, but its limited utility makes it nearly redundant. Its primary function applies in Grit Gate, where a pickaxe can achieve the same results without consuming a cybernetic slot.' },
        { name: 'Skillsoft', tier: 'D', slot: 'Head', sprite: 'Skillsoft_identified.png', review: 'All Skillsoft variants (Low SP, Medium SP, High SP, and Plus) provide access to skills ranging from single abilities to whole trees, depending on cost. However, consuming the head slot for skills that True Kin can learn more efficiently with skill points makes them largely redundant. Low-SP and Medium-SP variants are barely useful early game but become obsolete quickly. High SP or Plus variants can occasionally provide niche utility if granting rare, expensive, or hard-to-access skills like Multiweapon Mastery or Tinkering, but even these are situational and not worth the high cost for most builds.' },
        { name: 'Skin glitter', tier: 'D', cost: 1, slot: 'Face, Arm, Head, Hands, Feet', sprite: 'Skin_glitter_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Skin_glitter', review: 'Provides a 8% chance to refract light-based attacks, including lasers and Light Manipulation. However, light-based damage is rare, making this cybernetic highly situational and nearly useless in most encounters.' },
        { name: 'Skin glitter (high-tier)', tier: 'D', cost: 2, slot: 'Back, Body', sprite: 'Skin_glitter_(high-tier)_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Skin_glitter_(high-tier)', review: 'Provides a 16% chance to refract light-based attacks, including lasers and Light Manipulation. However, light-based damage is rare, making this cybernetic highly situational and nearly useless in most encounters.' },
        { name: 'Ultra-elastic ankle tendons', tier: 'D', cost: 3, slot: 'Feet', sprite: 'Ultraelastic_ankle_tendons_identified.png', wiki: 'https://wiki.cavesofqud.com/wiki/Ultra-elastic_ankle_tendons', review: 'Grants +10 move speed, which is an underwhelming improvement over the earlier Hyper-Elastic Ankle Tendons. The increase is minimal and provides little utility, especially compared to better mobility or combat-oriented cybernetics. With its low impact and access to stronger feet-slot options, it\'s an easy cybernetic to pass on.' },
  ],
};

export function findTierList(slug: string): TierList | undefined {
  if (slug === 'mutations') return MUTATIONS;
  if (slug === 'cybernetics') return CYBERNETICS;
  return undefined;
}
